class Solution:
    def rearrangeCharacters(self, s: str, target: str) -> int:
        s_count = {}
        target_count = {}

        for char in s:
            s_count[char] = s_count.get(char, 0) + 1

        for char in target:
            target_count[char] = target_count.get(char, 0) + 1

        max_copies = float('inf')
        for char, count in target_count.items():
            if char in s_count:
                max_copies = min(max_copies, s_count[char] // count)
            else:
                return 0

        return max_copies
